# Letter Glitch

Canvas grid of randomly glitching ASCII characters that cycle through a configurable character set, producing a digital static / hacker-terminal aesthetic as a full-viewport background.

## Use when
- Setting a dark, cyber aesthetic on a landing page or hero section.
- Filling a 404 or error page with atmospheric glitch noise.
- Creating a retro terminal visual break between page sections.

## Stack
- Framework: react
- Libraries: none

## Install
```bash
none
```

## Component — letter-glitch.tsx
```tsx
import React, { useEffect, useRef } from 'react';

export interface LetterGlitchProps {
  glitchColors?: string[];
  glitchSpeed?: number;
  centerVignette?: boolean;
  outerVignette?: boolean;
  smooth?: boolean;
  className?: string;
}

const LetterGlitch: React.FC<LetterGlitchProps> = ({
  glitchColors = ['#2b4539', '#61dca3', '#61b3dc'],
  glitchSpeed = 50,
  centerVignette = false,
  outerVignette = true,
  smooth = true,
  className = ''
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | null>(null);
  const lastGlitchTime = useRef<number>(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const fontSize = 16;
    const charSet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*()_+-=[]{}|;,.<>?';

    let cols: number, rows: number;
    let letters: Array<{ char: string; color: string; targetChar: string; progress: number }> = [];

    const resize = () => {
      canvas.width = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
      cols = Math.floor(canvas.width / fontSize);
      rows = Math.floor(canvas.height / fontSize);
      letters = Array.from({ length: cols * rows }, () => ({
        char: charSet[Math.floor(Math.random() * charSet.length)],
        color: glitchColors[Math.floor(Math.random() * glitchColors.length)],
        targetChar: charSet[Math.floor(Math.random() * charSet.length)],
        progress: Math.random()
      }));
    };

    const draw = (timestamp: number) => {
      const delta = timestamp - lastGlitchTime.current;
      if (delta < glitchSpeed) {
        animationRef.current = requestAnimationFrame(draw);
        return;
      }
      lastGlitchTime.current = timestamp;

      ctx.fillStyle = 'rgba(0,0,0,0.1)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.font = `${fontSize}px monospace`;

      letters.forEach((letter, i) => {
        if (Math.random() < 0.03) {
          letter.targetChar = charSet[Math.floor(Math.random() * charSet.length)];
          letter.color = glitchColors[Math.floor(Math.random() * glitchColors.length)];
        }
        if (smooth) {
          letter.progress += 0.1;
          if (letter.progress >= 1) {
            letter.char = letter.targetChar;
            letter.progress = 0;
          }
        } else if (Math.random() < 0.1) {
          letter.char = letter.targetChar;
        }
        const x = (i % cols) * fontSize;
        const y = Math.floor(i / cols) * fontSize + fontSize;
        ctx.fillStyle = letter.color;
        ctx.fillText(letter.char, x, y);
      });

      if (outerVignette) {
        const vGrad = ctx.createRadialGradient(
          canvas.width / 2, canvas.height / 2, canvas.width * 0.4,
          canvas.width / 2, canvas.height / 2, canvas.width * 0.8
        );
        vGrad.addColorStop(0, 'rgba(0,0,0,0)');
        vGrad.addColorStop(1, 'rgba(0,0,0,0.8)');
        ctx.fillStyle = vGrad;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      if (centerVignette) {
        const cGrad = ctx.createRadialGradient(
          canvas.width / 2, canvas.height / 2, 0,
          canvas.width / 2, canvas.height / 2, canvas.width * 0.4
        );
        cGrad.addColorStop(0, 'rgba(0,0,0,0.8)');
        cGrad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = cGrad;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      animationRef.current = requestAnimationFrame(draw);
    };

    resize();
    window.addEventListener('resize', resize);
    animationRef.current = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener('resize', resize);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [glitchColors, glitchSpeed, centerVignette, outerVignette, smooth]);

  return (
    <canvas
      ref={canvasRef}
      className={`w-full h-full block ${className}`}
    />
  );
};

export default LetterGlitch;
```

## Demo
```tsx
import React from 'react';
import LetterGlitch from './Component';

export default function App() {
  return (
    <div className="w-full h-screen bg-black relative overflow-hidden">
      <LetterGlitch
        glitchColors={['#2b4539', '#61dca3', '#61b3dc']}
        glitchSpeed={50}
        outerVignette={true}
      />
    </div>
  );
}
